import React from 'react';

function Footer() {
  return (
    <footer style={{
      background: '#1e3a5f',
      color: 'white',
      padding: '20px',
      textAlign: 'center',
      fontSize: '13px',
      marginTop: 'auto'
    }}>
      <p style={{ margin: 0 }}>
        🎓 Smart Campus Ticketing System | IT3030 PAF 2026 | SLIIT
      </p>
    </footer>
  );
}

export default Footer;
